"use client";

import { useState } from "react";
import { FileSearch, Terminal, CheckCircle2, AlertTriangle, Send } from "lucide-react";
import { useRouter } from "next/navigation";

export default function LogAnalyzePage() {
  const router = useRouter();
  const [logText, setLogText] = useState("");
  const [category, setCategory] = useState("Network");
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<any>(null);

  const categories = ["Network", "Server", "OS", "Software"];

  const handleAnalyze = (e: React.FormEvent) => {
    e.preventDefault();
    if (!logText.trim()) return;

    setIsAnalyzing(true);
    setResult(null);

    // Mock Backend/LLM Call delay
    setTimeout(() => {
      setIsAnalyzing(false);
      setResult({
        status: category === "Network" ? "danger" : "normal",
        summary: category === "Network"
          ? "?듭떖 ?ㅼ쐞移??ы듃 Down 諛??몃옒????＜ 媛먯?"
          : "?뱀씠 ?ы빆 ?놁쓬",
        details: category === "Network"
          ? "?낅젰?섏떊 濡쒓렇 ?⑦꽩? 怨쇨굅 諛쒖깮?덈뜕 '肄붿뼱 ?ㅼ쐞移??ы듃 遺덈웾 ?μ븷(SR-2023-089)' ?щ?? 95% ?쇱튂?⑸땲?? 濡쒓렇 ??'Link-Down' 諛?'High Collision' ?ㅼ썙?쒓? 踰≫꽣 DB???대떦 ?щ?? 媛뺥븳 ?곌???蹂댁엯?덈떎."
          : "?꾨컲?곸씤 ?쒖뒪??濡쒓렇媛 ?뺤긽 踰붿쐞?낅땲?? 愿?⑤맂 怨쇨굅 ?μ븷 ?щ?媛 ?뺤씤?섏? ?딆븯?듬땲??",
        action: category === "Network"
          ? "利됱떆 ?덈퉬 ?ы듃濡??덉껜?섍퀬 ?뚮８???앹꽦?섏뿬 ?ㅽ듃?뚰겕 ?대떦?먯? ?묒뾽?섏떗?쒖삤."
          : "吏?띿쟻??紐⑤땲?곕쭅???좎??섏떗?쒖삤."
      });
    }, 2000);
  };

  return (
    <div className="w-full h-full pb-10 flex flex-col xl:flex-row gap-6">
      {/* Input Section */}
      <div className="flex-1 flex flex-col gap-4">
        <div className="mb-2">
          <h1 className="text-2xl font-bold tracking-tight text-white mb-1">Knowledge-Based Log Analyzer</h1>
          <p className="text-slate-400 text-sm">LLM 諛??щ궡 吏??RAG) 湲곕컲???ㅼ떆媛??μ븷 濡쒓렇 遺꾩꽍 ?쒖뒪??/p>
        </div>

        <form onSubmit={handleAnalyze} className="bg-slate-800 border border-slate-700 rounded-xl p-5 flex flex-col flex-1 h-full min-h-[500px]">
          {/* Category Toggle */}
          <div className="mb-4">
            <label className="text-sm font-semibold text-slate-300 block mb-2">Category Selection</label>
            <div className="flex flex-wrap gap-2">
              {categories.map(cat => (
                <button
                  key={cat}
                  type="button"
                  onClick={() => setCategory(cat)}
                  className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${category === cat
                      ? 'bg-emerald-500/20 text-emerald-400 border border-emerald-500/50 shadow-[0_0_15px_rgba(16,185,129,0.2)]'
                      : 'bg-slate-900 border border-slate-700 text-slate-400 hover:text-slate-200 hover:border-slate-500'
                    }`}
                >
                  {cat}
                </button>
              ))}
            </div>
          </div>

          {/* Log Textarea */}
          <div className="flex-1 flex flex-col mb-4">
            <label className="text-sm font-semibold text-slate-300 block mb-2 flex items-center gap-2">
              <Terminal className="w-4 h-4" /> Raw Log Data
            </label>
            <textarea
              required
              value={logText}
              onChange={(e) => setLogText(e.target.value)}
              placeholder="?ш린??愿?⑤맂 ?쒖뒪???μ븷 濡쒓렇瑜?遺숈뿬?ｌ뼱 二쇱꽭??.. (?? Error: eth0 link down, CPU Load Average: 12.5)"
              className="flex-1 w-full bg-slate-900 border border-slate-700 rounded-lg p-4 text-slate-300 font-mono text-sm focus:outline-none focus:border-emerald-500/50 focus:ring-1 focus:ring-emerald-500/50 resize-none transition-colors"
            />
          </div>

          <button
            type="submit"
            disabled={isAnalyzing || !logText.trim()}
            className="w-full py-3 rounded-lg bg-emerald-500 hover:bg-emerald-400 text-slate-900 font-bold transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2 shadow-[0_0_15px_rgba(16,185,129,0.3)]"
          >
            {isAnalyzing ? (
              <span className="animate-pulse">LLM is Analyzing & Searching RAG Data...</span>
            ) : (
              <>
                <FileSearch className="w-5 h-5" /> Start Analysis
              </>
            )}
          </button>
        </form>
      </div>

      {/* Result Section */}
      <div className="flex-1 flex flex-col pt-[72px]">
        {isAnalyzing ? (
          <div className="bg-slate-800/50 border border-slate-700 border-dashed rounded-xl p-5 flex flex-col items-center justify-center flex-1 text-emerald-500/50 transition-all">
            <div className="w-16 h-16 rounded-full border-t-2 border-b-2 border-emerald-500 animate-spin mb-4" />
            <p className="animate-pulse font-medium text-emerald-400">Searching through Knowledge Base...</p>
          </div>
        ) : result ? (
          <div className={`bg-slate-800 border rounded-xl p-6 flex-1 shadow-2xl relative overflow-hidden transition-all ${result.status === 'danger' ? 'border-red-500/50' : 'border-emerald-500/50'
            }`}>
            <div className={`absolute top-0 left-0 w-full h-1 ${result.status === 'danger' ? 'bg-red-500 shadow-[0_0_15px_rgba(239,68,68,0.8)]' : 'bg-emerald-500 shadow-[0_0_15px_rgba(16,185,129,0.8)]'}`} />

            <div className="flex items-center gap-3 mb-6">
              {result.status === 'danger' ? (
                <AlertTriangle className="w-8 h-8 text-red-500" />
              ) : (
                <CheckCircle2 className="w-8 h-8 text-emerald-500" />
              )}
              <h2 className={`text-xl font-bold ${result.status === 'danger' ? 'text-red-400' : 'text-emerald-400'}`}>
                {result.summary}
              </h2>
            </div>

            <div className="space-y-6">
              <div>
                <h3 className="text-sm font-semibold text-slate-400 mb-2 uppercase tracking-wide">LLM Analysis (RAG Match)</h3>
                <div className="bg-slate-900 border border-slate-700 rounded-lg p-4 text-slate-200 leading-relaxed font-medium">
                  {result.details}
                </div>
              </div>

              <div>
                <h3 className="text-sm font-semibold text-slate-400 mb-2 uppercase tracking-wide">Recommended Action</h3>
                <div className={`border rounded-lg p-4 font-bold leading-relaxed ${result.status === 'danger'
                    ? 'bg-red-500/10 border-red-500/30 text-red-300'
                    : 'bg-emerald-500/10 border-emerald-500/30 text-emerald-300'
                  }`}>
                  {result.action}
                </div>
              </div>
            </div>

            {result.status === 'danger' && (
              <button
                onClick={() => router.push("/war-room")}
                className="mt-8 w-full bg-red-600 hover:bg-red-500 text-white font-bold py-3 px-4 rounded-lg flex items-center justify-center gap-2 transition-colors focus:ring-4 focus:ring-red-500/30 shadow-[0_0_15px_rgba(239,68,68,0.3)] hover:shadow-[0_0_20px_rgba(239,68,68,0.5)]"
              >
                <Send className="w-4 h-4" /> Escalate to War Room
              </button>
            )}
          </div>
        ) : (
          <div className="bg-slate-800/30 border border-slate-700 border-dashed rounded-xl p-5 flex flex-col items-center justify-center flex-1 text-slate-500">
            <Terminal className="w-16 h-16 mb-4 opacity-20" />
            <p>Paste logs and Run Analysis to see results here.</p>
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import { useStore } from "@/store/useStore";
import { Plus, Trash2, Save } from "lucide-react";

export default function SettingsPage() {
    const { topologyNodes, setTopologyNodes } = useStore();
    const [newNodeName, setNewNodeName] = useState("");
    const [newNodeType, setNewNodeType] = useState("network");
    const [newNodeStatus, setNewNodeStatus] = useState("normal");

    const handleAddNode = (e: React.FormEvent) => {
        e.preventDefault();
        if (!newNodeName.trim()) return;

        const newId = Date.now().toString();
        const newNode = {
            id: newId,
            name: newNodeName,
            type: newNodeType,
            status: newNodeStatus,
            group: Math.floor(Math.random() * 4) + 1
        };

        setTopologyNodes([...topologyNodes, newNode]);
        setNewNodeName("");
    };

    const handleDeleteNode = (id: string) => {
        setTopologyNodes(topologyNodes.filter(node => node.id !== id));
    };

    const handleStatusChange = (id: string, status: string) => {
        setTopologyNodes(topologyNodes.map(node => node.id === id ? { ...node, status } : node));
    };

    return (
        <div className="w-full h-full pb-10">
            <div className="flex flex-col gap-2 mb-6">
                <h1 className="text-2xl font-bold tracking-tight text-white">Infrastructure Settings</h1>
                <p className="text-slate-400">Manage connected devices and simulate status changes.</p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                {/* Added New Device Form */}
                <div className="bg-slate-800 border border-slate-700 p-5 rounded-xl h-fit">
                    <h3 className="text-lg font-semibold text-slate-200 mb-4">Add Device</h3>
                    <form onSubmit={handleAddNode} className="space-y-4">
                        <div>
                            <label className="block text-sm font-medium text-slate-300 mb-1">Device Name</label>
                            <input
                                type="text"
                                value={newNodeName}
                                onChange={(e) => setNewNodeName(e.target.value)}
                                className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-slate-200"
                                placeholder="e.g., Switch 02"
                            />
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-slate-300 mb-1">Type</label>
                            <select
                                value={newNodeType}
                                onChange={(e) => setNewNodeType(e.target.value)}
                                className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-slate-200"
                            >
                                <option value="network">Network / Switch</option>
                                <option value="cloud">Cloud Controller</option>
                                <option value="container">Docker Container</option>
                                <option value="database">Database Server</option>
                            </select>
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-slate-300 mb-1">Initial Status</label>
                            <select
                                value={newNodeStatus}
                                onChange={(e) => setNewNodeStatus(e.target.value)}
                                className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-slate-200"
                            >
                                <option value="normal">Normal</option>
                                <option value="warning">Warning</option>
                                <option value="danger">Danger</option>
                            </select>
                        </div>

                        <button
                            type="submit"
                            className="w-full bg-emerald-500 hover:bg-emerald-400 text-slate-900 font-bold py-2 px-4 rounded-lg flex justify-center items-center gap-2"
                        >
                            <Plus className="w-4 h-4" /> Add Device
                        </button>
                    </form>
                </div>

                {/* Existing Devices List */}
                <div className="lg:col-span-2 bg-slate-800 border border-slate-700 p-5 rounded-xl">
                    <h3 className="text-lg font-semibold text-slate-200 mb-4">Connected Devices</h3>
                    <div className="overflow-x-auto">
                        <table className="w-full text-left">
                            <thead>
                                <tr className="border-b border-slate-700 text-slate-400 text-sm">
                                    <th className="pb-3 px-4 font-medium">Device Name</th>
                                    <th className="pb-3 px-4 font-medium">Type</th>
                                    <th className="pb-3 px-4 font-medium">Status</th>
                                    <th className="pb-3 px-4 font-medium text-right">Actions</th>
                                </tr>
                            </thead>
                            <tbody>
                                {topologyNodes.map((node) => (
                                    <tr key={node.id} className="border-b border-slate-700/50 hover:bg-slate-700/20 transition-colors">
                                        <td className="py-3 px-4 font-medium text-slate-200">{node.name}</td>
                                        <td className="py-3 px-4 text-slate-400 capitalize">{node.type}</td>
                                        <td className="py-3 px-4">
                                            <select
                                                value={node.status}
                                                onChange={(e) => handleStatusChange(node.id, e.target.value)}
                                                className={`bg-slate-900 border rounded px-2 py-1 text-xs font-semibold
                          ${node.status === 'normal' ? 'text-emerald-400 border-emerald-500/50' :
                                                        node.status === 'warning' ? 'text-amber-400 border-amber-500/50' :
                                                            'text-red-400 border-red-500/50'}
                        `}
                                            >
                                                <option value="normal">Normal</option>
                                                <option value="warning">Warning</option>
                                                <option value="danger">Danger</option>
                                            </select>
                                        </td>
                                        <td className="py-3 px-4 text-right">
                                            <button
                                                onClick={() => handleDeleteNode(node.id)}
                                                className="text-slate-500 hover:text-red-400 p-1 rounded transition-colors"
                                            >
                                                <Trash2 className="w-4 h-4" />
                                            </button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                        {topologyNodes.length === 0 && (
                            <div className="text-center py-8 text-slate-500">No devices connected.</div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
}

