                            contentStyle={{ backgroundColor: '#1e293b', borderColor: '#334155', color: '#f8fafc', borderRadius: '8px' }}
                            itemStyle={{ color: '#f8fafc' }}
                        />
                        <Area type="monotone" dataKey="cpu" name="CPU (%)" stroke="#ef4444" fillOpacity={1} fill="url(#colorCpu)" />
                        <Area type="monotone" dataKey="memory" name="Memory (%)" stroke="#f59e0b" fillOpacity={1} fill="url(#colorMemory)" />
                    </AreaChart>
                </ResponsiveContainer>
            </div>
        </div>
    );
}

